// src/TicketHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function TicketHistory({ employee }) {
  const navigate = useNavigate();
  const [ticketExpenses, setTicketExpenses] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee) fetchData();
  }, [employee]);

  const fetchData = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const res = await fetch(
        `${apiBase}/ticket-expenses?empId=${encodeURIComponent(empId)}`
      );

      const data = await res.json();
      console.log("TICKET RESPONSE:", data);

      setTicketExpenses(Array.isArray(data) ? data : []);
    } catch {
      setTicketExpenses([]);
    }
  };

  const filtered = ticketExpenses.filter((t) => {
    const d = t.ticket_date?.split?.("T")?.[0] || t.ticket_date;
    if (startDate && d < startDate) return false;
    if (endDate && d > endDate) return false;
    return true;
  });

  const deleteTicket = async (id) => {
    if (!window.confirm("Delete ticket?")) return;

    const res = await fetch(`${apiBase}/ticket-expenses/${id}`, {
      method: "DELETE",
    });

    const data = await res.json();
    if (data.success) {
      setTicketExpenses((prev) => prev.filter((x) => x.id !== id));
    }
  };

  const editTicket = async (row) => {
    const newDate =
      window.prompt("Date:", row.ticket_date?.split?.("T")?.[0]) ||
      row.ticket_date;

    const newPurpose =
      window.prompt("Purpose:", row.purpose) || row.purpose;

    const newAssign =
      window.prompt("Assigned To:", row.assigned_to) ||
      row.assigned_to;

    const newAmount =
      window.prompt("Amount:", row.amount) || row.amount;

    const res = await fetch(`${apiBase}/ticket-expenses/${row.id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        ticket_date: newDate,
        purpose: newPurpose,
        assigned_to: newAssign,
        amount: newAmount,
      }),
    });

    const data = await res.json();

    if (data.success) {
      setTicketExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                ticket_date: newDate,
                purpose: newPurpose,
                assigned_to: newAssign,
                amount: newAmount,
              }
            : t
        )
      );
    }
  };

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button style={backBtn} onClick={() => navigate("/history")}>⬅ Back</button>
          <h2 style={title}>Ticket Expense History</h2>
        </div>

        <p style={empInfo}>
          {employee.name} • {employee.empId || employee.empld}
        </p>

        <div style={filterBar}>
          <div>
            <span>From</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div>
            <span>To</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear
          </button>
        </div>

        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Assigned To</th>
              <th>Amount</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {filtered.map((t) => (
              <tr key={t.id}>
                <td>{t.ticket_date?.split?.("T")?.[0]}</td>
                <td>{t.purpose}</td>
                <td>{t.assigned_to}</td>
                <td>₹{t.amount}</td>
                <td>
                  <button style={editBtn} onClick={() => editTicket(t)}>Edit</button>
                  <button style={delBtn} onClick={() => deleteTicket(t.id)}>Delete</button>
                </td>
              </tr>
            ))}

            {filtered.length === 0 && (
              <tr>
                <td colSpan="5" style={noData}>No ticket records found.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
